import os, signal, glob, time, subprocess
for pidfile in ['/tmp/vm.pid','/tmp/doomnative.pid']:
    try:
        pid=int(open(pidfile).read().strip())
        os.kill(pid, signal.SIGTERM)
    except Exception:
        pass
time.sleep(0.5)
for p in glob.glob('/tmp/frame*.bmp'):
    try: os.unlink(p)
    except: pass
for p in ['/tmp/vm.log','/tmp/vm.pid','/tmp/frame.bmp']:
    try: os.unlink(p)
    except: pass
proc = subprocess.Popen(['node','/app/vm.js'], cwd='/app', stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
open('/tmp/vm.pid','w').write(str(proc.pid))
for _ in range(60):
    if os.path.exists('/tmp/frame.bmp') and os.path.exists('/tmp/frame_000000.bmp'):
        break
    time.sleep(0.1)
print('pid', proc.pid)
print('frame_bmp', os.path.exists('/tmp/frame.bmp'))
print('frame_000000', os.path.exists('/tmp/frame_000000.bmp'))
print('alive', proc.poll() is None)
